import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';

function GenderCategory() {
  const { gender } = useParams();
  const navigate = useNavigate();
  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedCategory, setSelectedCategory] = useState('ALL');

  useEffect(() => {
    fetchProducts();
  }, [gender]);

  const fetchProducts = async () => {
    try {
      const res = await axios.get('/api/products');
      // Filter by gender
      const filtered = res.data.filter(p => p.gender === gender.toUpperCase());
      setProducts(filtered);
    } catch (error) {
      console.error('Error fetching products:', error);
    } finally {
      setLoading(false);
    }
  };

  // Get unique categories
  const categories = ['ALL', ...new Set(products.map(p => p.category))];

  // Filter products by selected category
  const filteredProducts = selectedCategory === 'ALL'
    ? products
    : products.filter(p => p.category === selectedCategory);

  const subCategoryItems = [
    'New Arrivals',
    'View All',
    'Featured',
    'Best Sellers',
    'Sale',
    'Sustainable',
  ];

  if (loading) return <div className="loading">Loading...</div>;

  return (
    <div style={{ display: 'flex', minHeight: 'calc(100vh - 70px)' }}>
      {/* Left Sidebar */}
      <div style={{
        width: '240px',
        backgroundColor: '#fff',
        padding: '50px 30px',
        borderRight: '1px solid #f0f0f0',
        position: 'sticky',
        top: '70px',
        height: 'calc(100vh - 70px)',
        overflowY: 'auto'
      }}>
        {/* Main Title */}
        <h2 style={{
          fontSize: '14px',
          fontFamily: 'Helvetica, Arial, sans-serif',
          fontWeight: '400',
          letterSpacing: '0.5px',
          textTransform: 'uppercase',
          color: '#000',
          margin: '0 0 40px 0',
          lineHeight: '1.4'
        }}>
          All {gender.toUpperCase()} Clothing
        </h2>

        {/* Subcategories - 5 items */}
        <div style={{ marginBottom: '40px' }}>
          {subCategoryItems.slice(0, 5).map((item) => (
            <div
              key={item}
              style={{
                fontSize: '13px',
                fontFamily: 'Helvetica, Arial, sans-serif',
                fontWeight: '300',
                letterSpacing: '0.3px',
                color: '#000',
                padding: '14px 0',
                cursor: 'pointer',
                borderBottom: '1px solid #f5f5f5',
                transition: 'color 0.3s'
              }}
              onMouseEnter={(e) => e.target.style.color = '#999'}
              onMouseLeave={(e) => e.target.style.color = '#000'}
            >
              {item}
            </div>
          ))}
        </div>

        {/* Categories Section */}
        <div style={{ borderTop: '1px solid #f0f0f0', paddingTop: '30px' }}>
          <div style={{
            fontSize: '11px',
            fontFamily: 'Helvetica, Arial, sans-serif',
            fontWeight: '400',
            letterSpacing: '0.5px',
            textTransform: 'uppercase',
            color: '#999',
            marginBottom: '25px'
          }}>
            FILTER BY CATEGORY
          </div>

          {categories.map((cat) => (
            <div
              key={cat}
              onClick={() => setSelectedCategory(cat)}
              style={{
                fontSize: '12px',
                fontFamily: 'Helvetica, Arial, sans-serif',
                fontWeight: selectedCategory === cat ? '400' : '300',
                letterSpacing: '0.3px',
                color: selectedCategory === cat ? '#000' : '#999',
                padding: '12px 0',
                cursor: 'pointer',
                borderBottom: '1px solid #f5f5f5',
                transition: 'color 0.3s'
              }}
              onMouseEnter={(e) => !selectedCategory === cat && (e.target.style.color = '#000')}
              onMouseLeave={(e) => !selectedCategory === cat && (e.target.style.color = '#999')}
            >
              {cat}
            </div>
          ))}
        </div>
      </div>

      {/* Main Content */}
      <div style={{ flex: 1, backgroundColor: '#fff' }}>
        {/* Header */}
        <div style={{
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'center',
          padding: '30px 30px',
          borderBottom: '1px solid #f0f0f0'
        }}>
          <h1 style={{
            fontSize: '24px',
            fontFamily: 'Helvetica, Arial, sans-serif',
            fontWeight: '300',
            letterSpacing: '1px',
            color: '#000',
            margin: '0',
            textTransform: 'uppercase'
          }}>
            {selectedCategory === 'ALL' ? gender.toUpperCase() : selectedCategory}
          </h1>
          <div style={{
            fontSize: '11px',
            fontFamily: 'Helvetica, Arial, sans-serif',
            letterSpacing: '0.5px',
            color: '#000',
            cursor: 'pointer'
          }}>
            FILTER BY +
          </div>
        </div>

        {/* Products Grid - 1000x1400 format (3 columns) */}
        <div style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(3, 1fr)',
          gap: '0',
          padding: '0'
        }}>
          {filteredProducts.map((product) => (
            <div key={product._id} style={{
              borderRight: '1px solid #f0f0f0',
              borderBottom: '1px solid #f0f0f0'
            }}>
              {/* Image Container - 1000x1400 aspect ratio */}
              <div style={{
                aspectRatio: '1000 / 1400',
                backgroundColor: '#f9f9f9',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                overflow: 'hidden',
                cursor: 'pointer'
              }}>
                <img
                  src={product.media?.featured || `/products/${product._id}.jpg`}
                  alt={product.name}
                  style={{
                    width: '100%',
                    height: '100%',
                    objectFit: 'cover'
                  }}
                />
              </div>

              {/* Product Info */}
              <div style={{
                padding: '20px',
                borderRight: '1px solid #f0f0f0',
                borderBottom: '1px solid #f0f0f0'
              }}>
                <h3 style={{
                  fontSize: '13px',
                  fontFamily: 'Helvetica, Arial, sans-serif',
                  fontWeight: '400',
                  letterSpacing: '0.5px',
                  color: '#000',
                  margin: '0 0 10px 0',
                  textTransform: 'uppercase'
                }}>
                  {product.name}
                </h3>
                <p style={{
                  fontSize: '13px',
                  fontFamily: 'Helvetica, Arial, sans-serif',
                  fontWeight: '500',
                  color: '#000',
                  margin: '0',
                  letterSpacing: '0.5px'
                }}>
                  ${product.price}
                </p>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

export default GenderCategory;
